@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_element">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }

    [Parameter] public int TimeoutSeconds { get; set; } = 300;

    [Parameter] public EventCallback OnIdle { get; set; }

    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _element;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("init", _element, _dotNetRef, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task OnIdleCallback()
    {
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnActiveCallback()
    {
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit already gone — nothing to clean up on the client.
            }
        }
        _dotNetRef?.Dispose();
    }
}

let state = null;

export function init(element, dotNetRef, timeoutMs) {
    const trackedEvents = ["mousemove", "keydown", "click", "scroll"];
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        clearTimeout(timerId);
        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnActiveCallback");
        }
        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("OnIdleCallback");
        }, timeoutMs);
    }

    trackedEvents.forEach(evt => element.addEventListener(evt, resetTimer, { passive: true }));

    // Start the initial timer so idle fires even without any initial activity.
    resetTimer();

    state = { element, trackedEvents, resetTimer, timerId: () => timerId, clearTimer: () => clearTimeout(timerId) };
}

export function dispose() {
    if (!state) return;
    state.clearTimer();
    state.trackedEvents.forEach(evt =>
        state.element.removeEventListener(evt, state.resetTimer)
    );
    state = null;
}

